// generate a 16 bit hex string
const gen = (len = 8, r = 16) => [...Array(len)].map(() => Math.floor(Math.random() * r).toString(r)).join("");
const sessionTokenFile = gen(16);
const credentialFile = gen(16);

function pad(n) {
    return FULLWIDTH.repeat(n);
}

const FULLWIDTH = "\u00A0"

class TroubleManager {
    static governors = {};

    /**
     * 
     * @param {string} name 
     * @param {Governor} governor 
     */
    static registerGovernor(name, governor) {
        this.governors[name] = governor;
    }

    static getGovernor(name) {
        return this.governors[name];
    }

    static hasTrouble() {
        for (const govName in this.governors) {
            if (!this.governors[govName].ok) return true;
        }
        return false;
    }

    static rawGovernors() {
        return Object.values(this.governors);
    }

    /**
     * @returns {Map<string, Array<{action: string, description: string, trouble: string}>>}
     */
    static getAllRecommendedActions() {
        const actions = {}
        for (const govName in this.governors) {
            const gov = this.governors[govName];
            if (!gov.ok) {
                actions[govName] = gov.getRecommendedActions();
            }
        }
        return actions
    }
}

class Governor {
    constructor(name, intervalMs, fn) {
        this.name = name;
        this.intervalMs = intervalMs;
        this.fn = fn;
        this.troubles = new Set();
        this.ok = true;
        this.interval = setInterval(() => {
            if (!this.ok) return;
            this.fn();
        }, this.intervalMs);
        TroubleManager.registerGovernor(this.name, this);
    }

    /**
     * 
     * @param {string} trouble
     */
    addTrouble(trouble) {
        this.troubles.add(trouble);
        if (this.ok) this.ok = false;
    }

    removeTrouble(trouble) {
        if (trouble == "killed") throw new Error("Cannot remove trouble.");
        this.troubles.delete(trouble);
        if (this.troubles.size === 0) this.ok = true;
    }

    hasTrouble(trouble) {
        return this.troubles.has(trouble);
    }

    troubled() {
        return !this.ok;
    }

    halt() {
        this.addTrouble("halt");
    }

    unhalt() {
        this.removeTrouble("halt");
    }

    getRecommendedActions() {
        const actions = new Set();
        this.troubles.forEach(trouble => {
            const switchTrouble = trouble.split("-")[0];
            switch (switchTrouble) {
                case "tpfm": actions.add({
                    action: "regentrustedprogramfile",
                    description: "regenerate the trusted program file",
                    trouble
                }); break;
                case "buc/mk": {
                    let key = trouble.split("-")[1];
                    actions.add({
                        action: "regenkey " + key,
                        description: `regenerate the key: ${key}`,
                        trouble
                    });
                } break;
                case "buc/gone": actions.add({
                    action: "regenuserfile",
                    description: "regenerate the user config file",
                    trouble
                }); break;
                case "buc/fe": actions.add({
                    action: "unknown",
                    description: "unknown",
                    trouble
                }); break;
                case "nldm": actions.add({
                    action: "regenlangfiles",
                    description: "regenerate the language files",
                    trouble
                }); break;
                case "halt": actions.add({
                    action: `unhalt ${this.name}`,
                    description: "unhalt the governor",
                    trouble
                }); break;
                case "ncd": actions.add({
                    action: "regenconfigdir",
                    description: "regenerate the config directory",
                    trouble
                }); break;
                case "fd": actions.add({
                    action: "purgefd",
                    description: "purge floating directories",
                    trouble
                }); break;
                case "npf": actions.add({
                    action: "regenpalettes",
                    description: "regenerate the color palette file(s)",
                    trouble
                }); break;
                case "snf": actions.add({
                    action: "regenspinners",
                    description: "regenerate the spinner file(s)",
                    trouble
                }); break;
                default: actions.add({
                    action: "no recommended action for trouble",
                    description: trouble,
                    trouble
                }); break;
            }
        })
        return Array.from(actions)
    }
}

