                const fn = stripped.substring(0, atIndex).trim();
                if (!fn) return '#document'; // empty = top-level script
                if (fn === "anonymous") return '<anonymous>';
                return fn.startsWith("async*") ? 'async ' + fn.substring(6) : fn;
